function parseCsvData(source: string): CsvCooperativeRow[] {
  const lines = source.split('\n').map((line) => line.trim());
  const [, ...rows] = lines;

  return rows
    .filter((line) => line.length > 0)
    .map((line) => {
      const parts = line.split(',').map((p) => p.trim());
      const [name, cercle, commune, douar, axis, specialty, xStr, yStr, lngStr, latStr] = parts;

      return {
        name: name ?? '',
        cercle: cercle ?? '',
        commune: commune ?? '',
        douar: douar ?? '',
        developmentAxis: axis ?? '',
        specialty: specialty ?? '',
        x: xStr ? Number(xStr) : undefined,
        y: yStr ? Number(yStr) : undefined,
        longitude: lngStr ? Number(lngStr) : undefined,
        latitude: latStr ? Number(latStr) : undefined,
      };
    });
}

function slugify(value: string): string {
  return value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-');
}

function buildAddress(row: CsvCooperativeRow): string {
  const parts: string[] = [];

  if (row.douar) parts.push(row.douar);
  if (row.commune) parts.push(row.commune);
  if (row.cercle) parts.push(`Cercle ${row.cercle}`);

  return parts.join(', ');
}

function mapAxisToCategory(axis: string, specialty: string): string {
  const axisLower = axis.toLowerCase();
  const specialtyLower = specialty.toLowerCase();

  if (axisLower.includes('elevage') || specialtyLower.includes('elevage')) {
    return 'Agriculture';
  }

  if (axisLower.includes('apiculture') || specialtyLower.includes('apiculture')) {
    return 'Terroir';
  }

  if (
    axisLower.includes('valorisation des produits locaux') ||
    specialtyLower.includes('patis') ||
    specialtyLower.includes('gateaux')
  ) {
    return 'Terroir';
  }

  return 'Terroir';
}

