/** Rotation du tableau d'images pour que chaque produit ait une image principale différente (images[0] varie). */
function rotateImageSet<T>(arr: T[], offset: number): T[] {
  if (arr.length === 0) return arr;
  const n = offset % arr.length;
  return [...arr.slice(n), ...arr.slice(0, n)];
}

function createProductsForCsvCoop(coopId: string, row: CsvCooperativeRow): Product[] {
  const address = buildAddress(row);
  const templates = getProductTemplatesForSpecialty(row.developmentAxis, row.specialty);
  // Utiliser la même image de couverture que la coopérative pour tous les produits
  const imageKey = pickImageSetKey(row.developmentAxis, row.specialty);
  const cooperativeCoverImage = getLocalCoverImagePathFromAxisSpecialty(
    row.developmentAxis,
    row.specialty,
    imageKey,
  );
  const productImages = [cooperativeCoverImage, cooperativeCoverImage, cooperativeCoverImage];

  return templates.map((t, i) => {
    const name = t.name;
    const longDesc = t.longDesc.replace(/{name}/g, row.name).replace(/{address}/g, address).replace(/{specialty}/g, row.specialty || row.developmentAxis);
    return {
      id: `p-${coopId}-${i + 1}`,
      name,
      price: t.price,
      images: productImages,
      alt: name,
      shortDescription: t.shortDesc + ` Coopérative ${row.name}.`,
      longDescription: longDesc,
      cooperativeId: coopId,
    };
  });
}

/** Génère le texte "Notre histoire" à partir des champs Excel (Cercle, Commune, Douar, Axe, Spécialité). */
function generateNotreHistoire(row: CsvCooperativeRow): string {
  const zone = (row.cercle?.trim() || '').toUpperCase();
  const addr = buildAddress(row);
  const axis = row.developmentAxis || 'activité locale';
  const spec = row.specialty || axis;

  return (
    `La coopérative ${row.name.trim()} a été créée dans le douar ${row.douar || '—'}, commune de ${row.commune || '—'}, dans le cercle de ${zone || '—'}. ` +
    `Spécialisée dans l’axe « ${axis} » et plus précisément dans « ${spec} », elle regroupe des producteurs et productrices locaux pour valoriser les savoir-faire et les ressources du territoire. ` +
    `Située à ${addr}, elle propose des produits issus de ${spec} et contribue au développement économique de la région. ` +
    `Aujourd’hui, ${row.name.trim()} met en avant la qualité et la traçabilité de ses productions.`
  );
}

function createCooperativesFromCsv(rows: CsvCooperativeRow[]): Cooperative[] {
  return rows.map((row, index) => {
    const id = `csv-${index + 1}`;
    // Cercle = zone (AKNOUL / TAINASTE), normalisé en majuscules pour cohérence
    const zone = (row.cercle?.trim() || 'Autre').toUpperCase();
    const address = buildAddress(row);
    const category = mapAxisToCategory(row.developmentAxis, row.specialty);
    const imageKey = pickImageSetKey(row.developmentAxis, row.specialty);
    // Varier l’image de couverture par coop pour éviter que toutes les coops (ex. Elevage Ovin) aient la même photo
    const hasCoords =
      row.latitude != null &&
      row.longitude != null &&
      Number.isFinite(row.latitude) &&
      Number.isFinite(row.longitude);

    return {
      id,
      name: row.name.trim(),
      slug: slugify(row.name),
      category,
      zone,
      location: {
        lat: hasCoords ? row.latitude! : Number.NaN,
        lng: hasCoords ? row.longitude! : Number.NaN,
        address,
      },
      descriptionShort: `${row.specialty || row.developmentAxis} à ${row.commune || zone}.`,
      descriptionLong: generateNotreHistoire(row),
      coverImage: getLocalCoverImagePathFromAxisSpecialty(row.developmentAxis, row.specialty, imageKey),
      coverAlt: row.specialty || row.developmentAxis,
      products: createProductsForCsvCoop(id, row),
      circle: row.cercle,
      commune: row.commune,
      douar: row.douar,
      developmentAxis: row.developmentAxis,
      specialty: row.specialty,
      x: row.x,
      y: row.y,
    };
  });
}

const csvRows = parseCsvData(rawCsvData);
const csvCooperatives = createCooperativesFromCsv(csvRows);

export const cooperatives: Cooperative[] = [...baseCooperatives, ...csvCooperatives];

/**
 * 4 grandes catégories (familles de produits) pour la page d'accueil,
 * dégagées des colonnes Axe de développement et Spécialité.
 */
export type ProductTypeSlug = 'apiculture' | 'terroir' | 'patisserie' | 'elevage';

export type ProductTypeInfo = {
  slug: ProductTypeSlug;
  label: string;
  description: string;
  image: string;
  alt: string;
};

export function coopMatchesProductType(coop: Cooperative, typeSlug: ProductTypeSlug): boolean {
  const axis = (coop.developmentAxis ?? '').toLowerCase();
  const spec = (coop.specialty ?? '').toLowerCase();
  switch (typeSlug) {
    case 'apiculture':
      return axis.includes('apiculture');
    case 'terroir':
      return (
        axis.includes('valorisation des produits locaux') ||
        spec.includes('pam') ||
        spec.includes('couscous') ||
        spec.includes('plantes aromatiques') ||
        spec.includes('séchage') ||
        spec.includes('sechage fruits') ||
        spec.includes('emballage') ||
        spec.includes("production d'emballage")
      );
    case 'patisserie':
      return (
        axis.includes('patisserie') ||
        axis.includes('patissereie') ||
        spec.includes('gateaux') ||
        spec.includes('patis')
      );
    case 'elevage':
      return (
        axis.includes('elevage ovin') ||
        spec.includes('elevage ovin') ||
        axis.includes('elevage poulet') ||
        spec.includes('elevage poulet') ||
        axis.includes('poulet') ||
        spec.includes('poulet')
      );
    default:
      return false;
  }
}

