export type ProductWithMeta = Product & {
  cooperativeSlug: string;
  cooperativeName?: string;
  zone: string;
  category?: string;
};

/** Retourne les produits des coopératives dont l'axe/spécialité correspond au type demandé */
export function getProductsByProductType(typeSlug: string): ProductWithMeta[] {
  const slug = typeSlug as ProductTypeSlug;
  if (!productTypes.some((t) => t.slug === slug)) return [];
  return cooperatives
    .filter((coop) => coopMatchesProductType(coop, slug))
    .flatMap((coop) =>
      coop.products.map((p) => ({
        ...p,
        cooperativeSlug: coop.slug,
        cooperativeName: coop.name,
        zone: coop.zone,
        category: coop.category,
      }))
    );
}

/** Méta pour la page catégorie/type (titre, image, style) */
export function getProductTypeMeta(typeSlug: string): ProductTypeInfo | undefined {
  return productTypes.find((t) => t.slug === typeSlug);
}
